// src/screens/scanner/CurrentValueHero.js — SCN86 extracted from Scanner.js
import React, { useState, useEffect, useMemo, useRef } from 'react';
import { T, SZ, CURRENCIES, fmtMoney } from '../../theme';
import { Card, Pill, Button, Spinner, LoadingCard, SectionLabel } from '../../components';
import { OP_RARITIES } from '../../rarities';
import { sortedSetsForLang, formatSetForQuery, setGroupLabel, inferSetFromCode } from '../../sets';
import * as helpers from './helpers';
const { isGradedTier, rawConditionGuess, pickGradedTwoPerTier, classifyTitleClient,
        convertCurrency, medianTHB, isDonCard, isCnAnnivCard, expandRarityTags,
        compactCondition, buildSummary } = helpers;

export default function CurrentValueHero({ allItems, fmt }) {
  // Bucket every listing into PSA 10 / Raw NM. BGS10/CGC10/lower grades
  // are excluded — they still appear in TradingHistory below.
  const { raw, psa10 } = useMemo(() => {
    const rawArr = [];
    const psa10Arr = [];
    for (const it of allItems) {
      const tier = it.conditionTier || classifyTitleClient(it.title);
      const title = ` ${String(it.title || '').toUpperCase()} `;
      if (tier === 'PSA 10' || /[^A-Z]PSA[\s.-]*10[^0-9]/.test(title)) {
        psa10Arr.push(it);
      } else if (tier === 'Raw') {
        rawArr.push(it);
      }
    }
    return { raw: rawArr, psa10: psa10Arr };
  }, [allItems]);

  const computeStats = (items) => {
    const prices = items.map((it) => it.priceUSD).filter((p) => p > 0).sort((a, b) => a - b);
    if (prices.length === 0) return null;
    const mid = Math.floor(prices.length / 2);
    const median = prices.length % 2 ? prices[mid] : (prices[mid - 1] + prices[mid]) / 2;
    const dated = items.filter((it) => it.soldDate)
      .sort((a, b) => new Date(b.soldDate) - new Date(a.soldDate));
    return {
      median,
      low:  prices[0],
      high: prices[prices.length - 1],
      count: prices.length,
      lastSold: dated[0] || items[0],
    };
  };

  const psaStats = useMemo(() => computeStats(psa10), [psa10]);
  const rawStats = useMemo(() => computeStats(raw),   [raw]);

  if (!psaStats && !rawStats) return null;

  const renderTile = (label, accent, stats) => {
    const color = accent === 'cyan' ? T.cyan : T.magenta;
    const gradient = accent === 'cyan' ? T.gradientPrimary : T.magenta;
    return (
      <div style={{
        flex: 1, minWidth: 0,
        background: T.surface2,
        border: `1px solid ${T.border2}`,
        borderRadius: 14,
        padding: '14px 14px',
        position: 'relative', overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0, height: 3,
          background: gradient,
        }} />
        <div style={{
          fontSize: SZ.xs, color: T.textLow, fontFamily: T.fontDisplay,
          fontWeight: 700, letterSpacing: '0.06em',
        }}>
          {label}
        </div>

        {stats ? (
          <>
            <div style={{
              fontSize: 28, fontWeight: 700, fontFamily: T.fontDisplay,
              color, lineHeight: 1.1, marginTop: 4,
              letterSpacing: '-0.01em',
              whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
            }}>
              {fmt(stats.median)}
            </div>
            <div style={{
              fontSize: 10, color: T.textDim, fontFamily: T.fontMono,
              marginTop: 2, display: 'flex', gap: 6, alignItems: 'center',
            }}>
              <span>median</span><span>·</span><span>{stats.count} sold</span>
            </div>

            {stats.low !== stats.high && (
              <div style={{ marginTop: 10 }}>
                <div style={{
                  position: 'relative', height: 6, background: T.bgDeep,
                  borderRadius: 999, overflow: 'visible',
                }}>
                  <div style={{
                    position: 'absolute', inset: 0,
                    background: `linear-gradient(90deg, ${color}33, ${color})`,
                    borderRadius: 999,
                  }} />
                  <div style={{
                    position: 'absolute',
                    left: `${((stats.median - stats.low) / (stats.high - stats.low)) * 100}%`,
                    top: -2, bottom: -2,
                    width: 2, background: T.textHi,
                    borderRadius: 2, transform: 'translateX(-50%)',
                  }} />
                </div>
                <div style={{
                  display: 'flex', justifyContent: 'space-between',
                  marginTop: 4, fontSize: 10, color: T.textLow,
                  fontFamily: T.fontMono,
                }}>
                  <span>{fmt(stats.low)}</span>
                  <span>{fmt(stats.high)}</span>
                </div>
              </div>
            )}

            {stats.lastSold && (
              <div style={{
                marginTop: 10, paddingTop: 8,
                borderTop: `1px solid ${T.border}`,
                fontSize: 10, color: T.textLow, fontFamily: T.fontMono,
                display: 'flex', justifyContent: 'space-between', gap: 6,
              }}>
                <span>last sold</span>
                <span style={{ color: T.textHi, fontWeight: 600 }}>
                  {fmt(stats.lastSold.priceUSD)}
                </span>
              </div>
            )}
          </>
        ) : (
          <div style={{
            fontSize: SZ.xs, color: T.textDim,
            marginTop: 8, padding: '14px 0', textAlign: 'center',
          }}>
            No sales found
          </div>
        )}
      </div>
    );
  };

  return (
    <div style={{ marginTop: 18 }}>
      <SectionLabel>CURRENT VALUE · BY GRADE</SectionLabel>
      <div style={{ display: 'flex', gap: 10, marginTop: 10 }}>
        {renderTile('PSA 10', 'cyan', psaStats)}
        {renderTile('RAW · NEAR MINT', 'magenta', rawStats)}
      </div>
    </div>
  );
}
